final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'NAT Gateway VPC Flow Logs monitoring dashboard with CloudWatch Logs Insights widgets for top source IPs by outbound traffic and rejected connections.'

Parameters:
  LogGroupName:
    Type: String
    Default: '/aws/vpc/flowlogs/nat'
    Description: 'The CloudWatch Logs group containing VPC Flow Logs for NAT Gateway.'
  TitlePrefix:
    Type: String
    Default: 'NAT Gateway'
    Description: 'Prefix for widget titles.'
  TimeRange:
    Type: String
    Default: 'P7D'
    Description: 'Time range for the widgets (ISO 8601 duration, e.g., P7D for past 7 days).'

Resources:
  NATGatewayFlowLogsDashboard:
    Type: 'AWS::CloudWatch::Dashboard'
    Properties:
      DashboardName: 'NATGatewayFlowLogsDashboard'
      DashboardBody: !Sub |
        {
          "widgets": [
            [
              {
                "type": "log",
                "properties": {
                  "title": "${TitlePrefix} - Top 10 Source IPs by Outbound Bytes",
                  "width": 12,
                  "height": 6,
                  "query": {
                    "id": "q1",
                    "region": "${AWS::Region}",
                    "queryString": "fields @timestamp, interfaceId, sourceAddress, bytes, action | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(bytes) as totalBytes by sourceAddress | sort totalBytes desc | limit 10"
                  },
                  "logGroups": [
                    {
                      "logGroupName": "${LogGroupName}"
                    }
                  ],
                  "view": "table",
                  "timeRange": {
                    "value": "${TimeRange}"
                  }
                }
              },
              {
                "type": "log",
                "properties": {
                  "title": "${TitlePrefix} - Top 10 Source IPs by Outbound Packets",
                  "width": 12,
                  "height": 6,
                  "query": {
                    "id": "q2",
                    "region": "${AWS::Region}",
                    "queryString": "fields @timestamp, interfaceId, sourceAddress, packets, action | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(packets) as totalPackets by sourceAddress | sort totalPackets desc | limit 10"
                  },
                  "logGroups": [
                    {
                      "logGroupName": "${LogGroupName}"
                    }
                  ],
                  "view": "table",
                  "timeRange": {
                    "value": "${TimeRange}"
                  }
                }
              }
            ],
            [
              {
                "type": "log",
                "properties": {
                  "title": "${TitlePrefix} - Top 10 Source IPs by Rejected Packets",
                  "width": 12,
                  "height": 6,
                  "query": {
                    "id": "q3",
                    "region": "${AWS::Region}",
                    "queryString": "fields @timestamp, interfaceId, sourceAddress, packets, action | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(packets) as rejectedPackets by sourceAddress | sort rejectedPackets desc | limit 10"
                  },
                  "logGroups": [
                    {
                      "logGroupName": "${LogGroupName}"
                    }
                  ],
                  "view": "table",
                  "timeRange": {
                    "value": "${TimeRange}"
                  }
                }
              },
              {
                "type": "log",
                "properties": {
                  "title": "${TitlePrefix} - Top 10 Source IPs by Rejected Bytes",
                  "width": 12,
                  "height": 6,
                  "query": {
                    "id": "q4",
                    "region": "${AWS::Region}",
                    "queryString": "fields @timestamp, interfaceId, sourceAddress, bytes, action | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(bytes) as rejectedBytes by sourceAddress | sort rejectedBytes desc | limit 10"
                  },
                  "logGroups": [
                    {
                      "logGroupName": "${LogGroupName}"
                    }
                  ],
                  "view": "table",
                  "timeRange": {
                    "value": "${TimeRange}"
                  }
                }
              }
            ]
          ]
        }

Outputs:
  DashboardName:
    Description: 'Name of the CloudWatch Dashboard'
    Value: !Ref 'NATGatewayFlowLogsDashboard'
  DashboardUrl:
    Description: 'Console URL for the CloudWatch Dashboard'
    Value: !Sub [
      'https://${AWS::Region}.console.aws.amazon.com/cloudwatch/home?region=${AWS::Region}#dashboards:name=${DashboardName}',
      {
        'DashboardName': !Ref NATGatewayFlowLogsDashboard
      }
    ]
  DashboardBody:
    Description: 'Dashboard body JSON'
    Value: !Sub |
      {
        "widgets": [
          [
            {
              "type": "log",
              "properties": {
                "title": "${TitlePrefix} - Top 10 Source IPs by Outbound Bytes",
                "width": 12,
                "height": 6,
                "query": {
                  "id": "q1",
                  "region": "${AWS::Region}",
                  "queryString": "fields @timestamp, interfaceId, sourceAddress, bytes, action | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(bytes) as totalBytes by sourceAddress | sort totalBytes desc | limit 10"
                },
                "logGroups": [
                  {
                    "logGroupName": "${LogGroupName}"
                  }
                ],
                "view": "table",
                "timeRange": {
                  "value": "${TimeRange}"
                }
              }
            },
            {
              "type": "log",
              "properties": {
                "title": "${TitlePrefix} - Top 10 Source IPs by Outbound Packets",
                "width": 12,
                "height": 6,
                "query": {
                  "id": "q2",
                  "region": "${AWS::Region}",
                  "queryString": "fields @timestamp, interfaceId, sourceAddress, packets, action | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(packets) as totalPackets by sourceAddress | sort totalPackets desc | limit 10"
                },
                "logGroups": [
                  {
                    "logGroupName": "${LogGroupName}"
                  }
                ],
                "view": "table",
                "timeRange": {
                  "value": "${TimeRange}"
                }
              }
            }
          ],
          [
            {
              "type": "log",
              "properties": {
                "title": "${TitlePrefix} - Top 10 Source IPs by Rejected Packets",
                "width": 12,
                "height": 6,
                "query": {
                  "id": "q3",
                  "region": "${AWS::Region}",
                  "queryString": "fields @timestamp, interfaceId, sourceAddress, packets, action | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(packets) as rejectedPackets by sourceAddress | sort rejectedPackets desc | limit 10"
                },
                "logGroups": [
                  {
                    "logGroupName": "${LogGroupName}"
                  }
                ],
                "view": "table",
                "timeRange": {
                  "value": "${TimeRange}"
                }
              }
            },
            {
              "type": "log",
              "properties": {
                "title": "${TitlePrefix} - Top 10 Source IPs by Rejected Bytes",
                "width": 12,
                "height": 6,
                "query": {
                  "id": "q4",
                  "region": "${AWS::Region}",
                  "queryString": "fields @timestamp, interfaceId, sourceAddress, bytes, action | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(bytes) as rejectedBytes by sourceAddress | sort rejectedBytes desc | limit 10"
                },
                "logGroups": [
                  {
                    "logGroupName": "${LogGroupName}"
                  }
                ],
                "view": "table",
                "timeRange": {
                  "value": "${TimeRange}"
                }
              }
            }
          ]
        ]
      }

