final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'CloudFormation template that provisions an S3 bucket with server-side encryption (SSE-KMS/CMK), versioning enabled, public access fully blocked, DeletionPolicy Retain, UpdateReplacePolicy Retain, and event-driven notifications to an encrypted SNS topic for s3:ObjectCreated:* events via CustomResource. Includes an SNS topic with policy allowing only this S3 bucket to publish messages.'

Resources:
  EventsBucket:
    Type: AWS::S3::Bucket
    DeletionPolicy: Retain
    UpdateReplacePolicy: Retain
    Properties:
      BucketName: !Sub '${AWS::StackName}-${AWS::AccountId}-${AWS::Region}-events-bucket'
      PublicAccessBlockConfiguration:
        BlockPublicAcls: true
        BlockPublicPolicy: true
        IgnorePublicAcls: true
        RestrictPublicBuckets: true
      BucketEncryption:
        BucketKeyEnabled: true
        ServerSideEncryptionConfiguration:
          - ServerSideEncryptionByDefault:
              SSEAlgorithm: aws:kms
              KmsMasterKeyID: !Ref S3SnsKmsKey
      VersioningConfiguration:
        Status: Enabled

  S3SnsKmsKey:
    Type: AWS::KMS::Key
    Properties:
      KeyPolicy:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              AWS: !Sub 'arn:aws:iam::${AWS::AccountId}:root'
            Action: 'kms:*'
            Resource: '*'
          - Effect: Allow
            Principal:
              Service: s3.amazonaws.com
            Action:
              - kms:GenerateDataKey*
              - kms:DescribeKey
            Resource: '*'
          - Effect: Allow
            Principal:
              Service: sns.amazonaws.com
            Action:
              - kms:GenerateDataKey*
              - kms:DescribeKey
            Resource: '*'

  S3EventNotificationsTopic:
    Type: AWS::SNS::Topic
    Properties:
      DisplayName: S3 Object Created Events
      KmsMasterKeyId: !Ref S3SnsKmsKey
      TopicName: S3EventNotificationsTopic

  SnsTopicPolicy:
    Type: AWS::SNS::TopicPolicy
    Properties:
      Topics:
        - !Ref S3EventNotificationsTopic
      PolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: s3.amazonaws.com
            Action: sns:Publish
            Resource: !Ref S3EventNotificationsTopic
            Condition:
              ArnLike:
                'aws:SourceArn': !GetAtt EventsBucket.Arn

  NotificationLambdaRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: lambda.amazonaws.com
            Action: sts:AssumeRole
      ManagedPolicyArns:
        - arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole
      Policies:
        - PolicyName: S3NotificationPolicy
          PolicyDocument:
            Version: '2012-10-17'
            Statement:
              - Effect: Allow
                Action: s3:PutBucketNotification
                Resource: !Sub 'arn:aws:s3:::${EventsBucket}'

  NotificationLambda:
    Type: AWS::Lambda::Function
    Properties:
      Handler: index.handler
      Role: !GetAtt NotificationLambdaRole.Arn
      Runtime: nodejs20.x
      Timeout: 60
      Code:
        ZipFile: |
          var https = require('https');
          var url = require('url');

          function sendResponse(event, context, responseStatus, responseData, physicalResourceId) {
            var responseBody = JSON.stringify({
              Status: responseStatus,
              Reason: "See the details in CloudWatch Log Stream: " + context.logStreamName,
              PhysicalResourceId: physicalResourceId || context.logStreamName,
              StackId: event.StackId,
              RequestId: event.RequestId,
              LogicalResourceId: event.LogicalResourceId,
              Data: responseData
            });

            var parsedUrl = url.parse(event.ResponseURL);
            var options = {
              hostname: parsedUrl.hostname,
              port: 443,
              path: parsedUrl.path,
              method: 'PUT',
              headers: {
                'content-type': '',
                'Content-Length': Buffer.byteLength(responseBody)
              }
            };

            var request = https.request(options, function(response) {
              console.log("Status Code: " + response.statusCode);
            });

            request.on('error', function(error) {
              console.log("sendResponse Error: " + error);
            });

            request.write(responseBody);
            request.end();
          }

          exports.handler = function(event, context) {
            var AWS = require('aws-sdk');
            var s3 = new AWS.S3({region: process.env.AWS_REGION});

            console.log("REQUEST RECEIVED:\n" + JSON.stringify(event));

            var responseStatus = "FAILED";
            var responseData = {};
            var physicalResourceId = "BucketNotification";
            var reason = "";

            try {
              var props = event.ResourceProperties;
              var bucketName = props.BucketName;
              var topicArn = props.TopicArn;
              var events = props.Events || ["s3:ObjectCreated:*"];

              physicalResourceId = "notification-" + bucketName;

              if (event.RequestType == "Delete") {
                s3.putBucketNotificationConfiguration({
                  Bucket: bucketName,
                  NotificationConfiguration: {}
                }, function(err, data) {
                  if (err) {
                    reason = "Delete failed: " + err.message;
                    console.log(reason);
                  } else {
                    responseStatus = "SUCCESS";
                  }
                  sendResponse(event, context, responseStatus, responseData, physicalResourceId);
                });
                return;
              } else { // Create or Update
                var notificationConfig = {
                  TopicConfigurations: [{
                    Id: "ObjectCreatedEvents",
                    Topic: topicArn,
                    Events: events
                  }]
                };

                s3.putBucketNotificationConfiguration({
                  Bucket: bucketName,
                  NotificationConfiguration: notificationConfig
                }, function(err, data) {
                  if (err) {
                    reason = "Put failed: " + err.message;
                    console.log(reason);
                  } else {
                    responseStatus = "SUCCESS";
                  }
                  sendResponse(event, context, responseStatus, responseData, physicalResourceId);
                });
                return;
              }
            } catch(err) {
              responseStatus = "FAILED";
              reason = "Exception: " + err.message;
              console.log(reason);
              sendResponse(event, context, responseStatus, responseData, physicalResourceId);
            }
          };

  BucketNotification:
    Type: AWS::CloudFormation::CustomResource
    DependsOn:
      - SnsTopicPolicy
    Properties:
      ServiceToken: !GetAtt NotificationLambda.Arn
      BucketName: !Ref EventsBucket
      TopicArn: !Ref S3EventNotificationsTopic
      Events:
        - s3:ObjectCreated:*

Outputs:
  S3BucketName:
    Description: Name of the S3 bucket
    Value: !Ref EventsBucket
  S3BucketArn:
    Description: ARN of the S3 bucket
    Value: !GetAtt EventsBucket.Arn
  SNSTopicArn:
    Description: ARN of the SNS topic
    Value: !Ref S3EventNotificationsTopic
  SNSTopicName:
    Description: Name of the SNS topic
    Value: !GetAtt S3EventNotificationsTopic.TopicName

