final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'Serverless calculator workflow using AWS Step Functions and Lambda which processes arithmetic operations (add, subtract, multiply, divide) based on dynamic input.'

Resources:
  LambdaExecutionRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: lambda.amazonaws.com
            Action: sts:AssumeRole
      MaxSessionDuration: 3600
      ManagedPolicyArns:
        - arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole

  CalculatorLogGroup:
    Type: AWS::Logs::LogGroup
    Properties:
      LogGroupName: /aws/lambda/Calculator
      RetentionInDays: 3

  Calculator:
    Type: AWS::Lambda::Function
    Properties:
      FunctionName: Calculator
      Runtime: nodejs20.x
      Handler: index.handler
      Role: !GetAtt LambdaExecutionRole.Arn
      Code:
        ZipFile: |
          exports.handler = async (event) => {
            const operator = event.operator;
            const [a, b] = event.operands;
            let result;
            switch (operator) {
              case 'add':
                result = a + b;
                break;
              case 'subtract':
                result = a - b;
                break;
              case 'multiply':
                result = a * b;
                break;
              case 'divide':
                if (b === 0) {
                  throw new Error('Division by zero');
                }
                result = a / b;
                break;
              default:
                throw new Error('Unsupported operator');
            }
            return { result };
          };

  StepFunctionsExecutionRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: states.amazonaws.com
            Action: sts:AssumeRole
      Policies:
        - PolicyName: InvokeCalculatorPolicy
          PolicyDocument:
            Version: '2012-10-17'
            Statement:
              - Effect: Allow
                Action: lambda:InvokeFunction
                Resource: !GetAtt Calculator.Arn

  CalculatorStateMachine:
    Type: AWS::StepFunctions::StateMachine
    Properties:
      StateMachineName: Calculator-StateMachine
      RoleArn: !GetAtt StepFunctionsExecutionRole.Arn
      StateMachineType: STANDARD
      DefinitionString:
        Fn::Sub:
          - |
            {
              "Comment": "A simple calculator workflow",
              "StartAt": "RouteOperation",
              "States": {
                "RouteOperation": {
                  "Type": "Choice",
                  "Choices": [
                    {
                      "Variable": "$.operator",
                      "StringEquals": "add",
                      "Next": "Add"
                    },
                    {
                      "Variable": "$.operator",
                      "StringEquals": "subtract",
                      "Next": "Subtract"
                    },
                    {
                      "Variable": "$.operator",
                      "StringEquals": "multiply",
                      "Next": "Multiply"
                    },
                    {
                      "Variable": "$.operator",
                      "StringEquals": "divide",
                      "Next": "Divide"
                    }
                  ],
                  "Default": "UnsupportedOperator"
                },
                "Add": {
                  "Type": "Task",
                  "Resource": "${CalculatorArn}",
                  "Parameters": {
                    "operator": "add",
                    "operands.$": "$.operands"
                  },
                  "End": true
                },
                "Subtract": {
                  "Type": "Task",
                  "Resource": "${CalculatorArn}",
                  "Parameters": {
                    "operator": "subtract",
                    "operands.$": "$.operands"
                  },
                  "End": true
                },
                "Multiply": {
                  "Type": "Task",
                  "Resource": "${CalculatorArn}",
                  "Parameters": {
                    "operator": "multiply",
                    "operands.$": "$.operands"
                  },
                  "End": true
                },
                "Divide": {
                  "Type": "Task",
                  "Resource": "${CalculatorArn}",
                  "Parameters": {
                    "operator": "divide",
                    "operands.$": "$.operands"
                  },
                  "End": true
                },
                "UnsupportedOperator": {
                  "Type": "Fail",
                  "Cause": "Unsupported arithmetic operator",
                  "Error": "InvalidInput"
                }
              }
            }
          - CalculatorArn: !GetAtt Calculator.Arn

Outputs:
  StateMachineArn:
    Description: ARN of the Calculator State Machine
    Value: !Ref CalculatorStateMachine
  CalculatorLambdaArn:
    Description: ARN of the Calculator Lambda Function
    Value: !GetAtt Calculator.Arn
